const { execSync } = require('child_process');

const filePath = $input.first().json.filePath;
const url = $input.first().json.url;
const id = $input.first().json.id;

// === RETRY CONFIG ===
// Паузы между попытками в секундах: 5с → 15с → 30с
// Всего 4 попытки (1 основная + 3 повтора)
const retries = [5, 15, 30];
let lastError = '';

for (let attempt = 0; attempt <= retries.length; attempt++) {
  try {
    const result = execSync(`curl -s https://api.groq.com/openai/v1/audio/transcriptions \
      -H "Authorization: Bearer put_your_key_here" \
      -H "Content-Type: multipart/form-data" \
      -F file="@${filePath}" \
      -F model="whisper-large-v3" \
      -F language="ru"`, {
      timeout: 300000
    });

    const response = JSON.parse(result.toString());

    // Проверка: API вернул ответ, но внутри JSON ошибка
    if (response.error) {
      throw new Error(response.error.message || JSON.stringify(response.error));
    }

    return [{
      json: {
        success: true,
        transcript: response.text,
        filePath: filePath,
        url: url,
        id: id
      }
    }];
  } catch (error) {
    lastError = error.message;
    // === RETRY BACKOFF ===
    // Если есть ещё попытки — ждём перед следующей
    if (attempt < retries.length) {
      execSync(`sleep ${retries[attempt]}`); // пауза 5с / 15с / 30с
    }
  }
}

// Все попытки исчерпаны — бросаем ошибку, чтобы сработал Error Workflow
throw new Error(`Whisper API failed after ${retries.length + 1} attempts: ${lastError}`);

const { execSync } = require('child_process');

// Получаем данные из вебхука
const url = $input.first().json.body.url;
const id = $input.first().json.body.id || 'audio';
const outputPath = `/home/node/downloads/${id}.mp3`;

// === RETRY CONFIG ===
// 3 попытки, пауза 3 секунды между ними
const maxRetries = 3;
const delaySeconds = 3;

let lastError = '';

for (let attempt = 1; attempt <= maxRetries; attempt++) {
  try {
    // Скачиваем аудио: -x извлечь аудио, --audio-format mp3 конвертировать в mp3
    execSync(`yt-dlp -x --audio-format mp3 -o "${outputPath}" "${url}"`, {
      timeout: 300000 // таймаут 5 минут
    });

    return [{
      json: {
        success: true,
        filePath: outputPath,
        url: url,
        id: id
      }
    }];
  } catch (error) {
    lastError = error.message;
    // === RETRY BACKOFF ===
    // Если есть ещё попытки — ждём перед следующей
    if (attempt < maxRetries) {
      execSync(`sleep ${delaySeconds}`);
    }
  }
}

// Все попытки исчерпаны — бросаем ошибку, чтобы сработал Error Workflow
throw new Error(`yt-dlp failed after ${maxRetries} attempts: ${lastError}`);

const { execSync } = require('child_process');

const filePath = $('Download audio').first().json.filePath;

try {
  execSync(`rm -f "${filePath}"`);
  return [{ json: { cleaned: true, filePath: filePath } }];
} catch (error) {
  return [{ json: { cleaned: false, error: error.message } }];
}
